  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Zeitleiste des Perpetual-Futures-Wettlaufs bei Prediction Markets</text>
  <text x="20" y="54" fill="#a1a1aa" font-size="12.5" font-family="sans-serif">Von Polymarkets Ankündigung bis Pascals Serie A</text>
  <g font-family="sans-serif">
    <line x1="60" y1="200" x2="650" y2="200" stroke="#3f3f46" stroke-width="2"/>
    <circle cx="90" cy="200" r="7" fill="#f87171"/>
    <circle cx="220" cy="200" r="7" fill="#fbbf24"/>
    <circle cx="350" cy="200" r="7" fill="#c4b5fd"/>
    <circle cx="480" cy="200" r="7" fill="#7dd3fc"/>
    <circle cx="610" cy="200" r="7" fill="#22d3ee"/>
    <text x="90" y="175" fill="#fca5a5" font-size="13" font-weight="700" text-anchor="middle">21.4.</text>
    <text x="90" y="228" fill="#e4e4e7" font-size="12.5" text-anchor="middle">Polymarket</text>
